    justify-content: space-between;
    align-items: center;
    padding: 0 20px; /* Padding for smaller screens */
}

.logo {
    font-family: 'Billabong', cursive; /* Placeholder for Instagram's custom font */
    font-size: 28px;
    font-weight: normal;
    color: #262626;
}

.search-box {
    position: relative;
}

.search-box input {
    background-color: #efefef;
    border: 1px solid #dbdbdb;
    border-radius: 8px;
    padding: 7px 10px;
    padding-left: 28px; /* Space for a search icon */
    font-size: 14px;
    outline: none;
    width: 215px;
    text-align: center;
    color: #8e8e8e;
}

.search-box::before {
    content: "🔍"; /* Magnifying glass emoji */
    position: absolute;
    left: 8px;
    top: 50%;
    transform: translateY(-50%);
    font-size: 14px;
    color: #8e8e8e;
}

.nav-icons a {
    color: #262626;
    font-size: 22px;
    margin-left: 22px;
    text-decoration: none;
    vertical-align: middle; /* Align icons with profile image */
}

.profile-icon {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background-image: url('https://via.placeholder.com/150/CCCCCC/FFFFFF?text=P'); /* Example profile image */
    display: inline-block;
}

/* Main Content Layout */
.main-content {
    display: flex;
    max-width: 935px;
    margin-top: 84px; /* Space for fixed navbar */
    margin-bottom: 40px;
    gap: 28px; /* Space between feed and sidebar */
    width: 100%;
    padding: 0 20px; /* Padding for overall content */
}

.feed-section {
    flex: 1; /* Takes up available space */
    max-width: 614px; /* Instagram's typical feed width */
}

.sidebar {
    width: 293px; /* Instagram's typical sidebar width */
