    top: 112px; /* Adjust based on navbar height + some margin */
    height: fit-content; /* Only takes up space of its content */
    align-self: flex-start; /* Aligns to the top of the main-content */
}

/* Stories */
.stories-container {
    background-color: #fff;
    border: 1px solid #dbdbdb;
    border-radius: 8px;
    padding: 16px 0;
    margin-bottom: 24px;
    display: flex;
    overflow-x: scroll; /* Allows horizontal scrolling */
    -ms-overflow-style: none;  /* IE and Edge hide scrollbar */
    scrollbar-width: none;  /* Firefox hide scrollbar */
}
.stories-container::-webkit-scrollbar {
    display: none; /* Chrome, Safari, Opera hide scrollbar */
}

.story {
